from collections import defaultdict, deque

def max_flow(graph, source, sink):
    """
    graph: dict of dicts {u: {v: capacity}}
    Modifies graph in place (residual). Returns max flow value.
    """
    def bfs():
        visited = {source}
        parent  = {source: None}
        queue   = deque([source])
        while queue:
            u = queue.popleft()
            for v, cap in graph[u].items():
                if v not in visited and cap > 0:
                    visited.add(v)
                    parent[v] = u
                    if v == sink:
                        return parent
                    queue.append(v)
        return None

    total = 0
    while (parent := bfs()) is not None:
        # Find bottleneck capacity along the path
        path_flow = float('inf')
        v = sink
        while v != source:
            u = parent[v]
            path_flow = min(path_flow, graph[u][v])
            v = u
        # Augment along the path
        v = sink
        while v != source:
            u = parent[v]
            graph[u][v]           -= path_flow
            graph[v][___________] += path_flow   # update reverse edge
            v = u
        total += path_flow
    return total
